import React, { useState } from "react";
import { uploadFile, fetchGoogleSheet } from "../services/api";

function Upload({ setUrls }) {
  const [file, setFile] = useState(null);
  const [sheetUrl, setSheetUrl] = useState("");

  // ✅ FORM SUBMIT HANDLER
  const handleUpload = async (e) => {
    e.preventDefault(); // 🔥 THIS STOPS PAGE RELOAD

    if (!file) {
      alert("Select file first");
      return;
    }

    try {
      const res = await uploadFile(file);
      setUrls(res.data.urls);
    } catch (err) {
      console.error(err);
    }
  };

  const handleGoogleSheet = async (e) => {
    e.preventDefault(); // 🔥 ALSO IMPORTANT

    if (!sheetUrl) {
      alert("Enter URL first");
      return;
    }

    try {
      const res = await fetchGoogleSheet(sheetUrl);
      setUrls(res.data.urls);
    } catch (err) {
      console.error(err.response?.data || err.message);
    }
  };

  return (
    <div>
      {/* ✅ IMPORTANT: USE FORM */}
      <form onSubmit={handleUpload}>
        <input
          type="file"
          onChange={(e) => setFile(e.target.files[0])}
        />

        <button type="submit">
          Upload File
        </button>
      </form>

      <br />

      <form onSubmit={handleGoogleSheet}>
        <input
          type="text"
          placeholder="Paste Google Sheet URL"
          value={sheetUrl}
          onChange={(e) => setSheetUrl(e.target.value)}
        />

        <button type="submit">
          Load Sheet
        </button>
      </form>
    </div>
  );
}

export default Upload;
